   import * as fs from "fs";

   class MinHeap {
     private data: number[] = [];
     get size(): number { return this.data.length; }
     push(val: number): void {
       this.data.push(val);
       let i = this.data.length - 1;
       while (i > 0) {
         const parent = (i - 1) >> 1;
         if (this.data[parent] <= this.data[i]) break;
         [this.data[parent], this.data[i]] = [this.data[i], this.data[parent]];
